#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char s[200005]; scanf("%s", s);
        int i = 0;
        while (i < N && s[i] == '1') i++;
        int cnt1 = i;
        int maxRun = 0, cur = 0;
        for (; i < N; ++i) {
            if (s[i] == '1') {
                cur++;
            } else {
                if (cur > maxRun) maxRun = cur;
                cur = 0;
            }
        }
        if (cur > maxRun) maxRun = cur;
        printf("%d\n", cnt1 + maxRun);
    }
    return 0;
}

