#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        s = next(it).strip()
        i = 0
        while i < N and s[i] == '1':
            i += 1
        cnt1 = i
        max_run = cur = 0
        while i < N:
            if s[i] == '1':
                cur += 1
            else:
                if cur > max_run:
                    max_run = cur
                cur = 0
            i += 1
        if cur > max_run:
            max_run = cur
        out_lines.append(str(cnt1 + max_run))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

